#-----------------------------------------------------------------------------------------------------#
# 							3. Process bedmethyl data                            ----
#-----------------------------------------------------------------------------------------------------#

# Create list of bedmethyl files to import
temp = list.files(s_bedfiles_folder, pattern="\\.bed$", full.names = TRUE)
cat(paste0("number of samples: " , length(temp)))

pblapply(temp, function(x) {
  
  # Load bedmethyl file and select relevant columns
  bedfile <- tryCatch({fread(x, header = FALSE, sep="\t",stringsAsFactors=FALSE, quote="",
                             colClasses =c("character", "integer", "NULL", "character", "numeric",
                                           "NULL", "NULL", "NULL", "NULL", "NULL", "numeric",
                                           "integer", "integer", "NULL", "NULL", "NULL", "NULL", "NULL"))
  }, error = function(e) {
    warning(paste("Error reading file:", x, "-", e$message))
    return(NULL)
  })
  
  if (is.null(bedfile)) return(NULL)

  # Rename columns of interest
  bedfile <- setNames(bedfile, c("chrom", "start_pos0", "mod_base_code","score",
                                 "percent_mod", "N_mod", "N_canon"))
  
  # Extract the base name of the file
  file_base_name <- sub("_filtered_SQK-NBD114-24", "",basename(x))
  
  # Extract postions
  position <- paste0(bedfile$chrom, "_", as.character(bedfile$start_pos0))

  # Extract 5mC values
  rows_with_m <- bedfile$mod_base_code== "m"
  methyl <- data.frame("position" = position[rows_with_m], "percent_mod" = bedfile$percent_mod[rows_with_m])
  methyl_count <- data.frame("position" = position[rows_with_m], "N_mod" = bedfile$N_mod[rows_with_m])
  
  # Extract 5hmC values
  rows_with_h <- bedfile$mod_base_code== "h"
  hydroxymethyl <- data.frame("position" = position[rows_with_h], "percent_mod" = bedfile$percent_mod[rows_with_h])
  hydroxymethyl_count <- data.frame("position" = position[rows_with_h], "N_mod" = bedfile$N_mod[rows_with_h])
  
  # Extract combined 5mC and 5hmC values
  modified_perc <- 100 - (bedfile$N_canon/bedfile$score)*100
  modified_perc <- unique(data.frame(position, modified_perc))
  
  # Extract combined 5mC and 5hmC counts
  modified_count <- bedfile$score - bedfile$N_canon
  modified_count <- unique(data.frame(position, modified_count))
  
  # Extract scores (number of calls)
  scores <- unique(data.frame(position, "scores" = as.numeric(bedfile$score)))
  
  # Save processed data
  bed_out_dir <- file.path(s_project_folder, "Bedmethyl")
  
  tryCatch(saveRDS(bedfile, file = file.path(bed_out_dir, paste0(file_base_name, ".rds"))), error = function(e) warning(e$message))
  tryCatch(saveRDS(methyl, file = file.path(bed_out_dir, paste0(file_base_name, "_methyl.rds"))), error = function(e) warning(e$message))
  tryCatch(saveRDS(hydroxymethyl, file = file.path(bed_out_dir, paste0(file_base_name, "_hydroxymethyl.rds"))), error = function(e) warning(e$message))
  tryCatch(saveRDS(modified_perc, file = file.path(bed_out_dir, paste0(file_base_name, "_modified.rds"))), error = function(e) warning(e$message))
  tryCatch(saveRDS(scores, file = file.path(bed_out_dir, paste0(file_base_name, "_scores.rds"))), error = function(e) warning(e$message))
  tryCatch(saveRDS(methyl_count, file = file.path(bed_out_dir, paste0(file_base_name, "_methyl_count.rds"))), error = function(e) warning(e$message))
  tryCatch(saveRDS(hydroxymethyl_count, file = file.path(bed_out_dir, paste0(file_base_name, "_hydroxymethyl_count.rds"))), error = function(e) warning(e$message))
  tryCatch(saveRDS(modified_count, file = file.path(bed_out_dir, paste0(file_base_name, "_modified_count.rds"))), error = function(e) warning(e$message))
  
  # Free up memory
  rm(bedfile, methyl, hydroxymethyl, modified_perc, scores, methyl_count, hydroxymethyl_count, modified_count)
  gc()
})


