#-----------------------------------------------------------------------------------------------------#
#					  5. Create dataframe for 5mC, 5hmC and canonical values       ----
#-----------------------------------------------------------------------------------------------------#

# Function for creating dataframes with CpGs (rows) and samples (columns)
combine_perc <- function(mod_type, chunk_size) {
  
  files = list.files(file.path(s_project_folder, "Bedmethyl/"), 
                    pattern=paste0("\\.bed_", mod_type, ".rds$"), 
                    full.names = TRUE)
  
  # calculate number of chunks
  files = split(files, ceiling(seq_along(files)/chunk_size))
  chunks = 1:length(files)
  
  sample_names = split(pheno_subset$CaseID, ceiling(seq_along(pheno_subset$CaseID)/chunk_size))
  
  cat("Number of samples: ", print(chunk_size*length(files)))
  
  # Merge samples
  pblapply(chunks, function(chunk) {
    
    temp <- files[[chunk]]
    
    bedfiles_chunk <- readRDS(temp[1]) # Start with first sample
    
    progress_bar <- txtProgressBar(min=0, max=length(temp)) # Add progress bar
    
    for (i in 2:length(temp)) {
      # Read BED file
      file <- readRDS(temp[i])
      file_base_name <- sub(".bam.bed.*", "", basename(temp[i]))
      
      # Combine methyl values
      bedfiles_chunk <- full_join(bedfiles_chunk, file, by = "position")
      colnames(bedfiles_chunk)[1] <- c("position")
      colnames(bedfiles_chunk)[i] <- sub(".bam.bed.*", "", basename(temp[i-1])) # existing data frame
      colnames(bedfiles_chunk)[i+1] <- sub(".bam.bed.*", "", basename(temp[i])) # new data frame
      
      rm(file)
      gc()
      
      setTxtProgressBar(progress_bar, value = i)
    }
    
    # Move position values to rownames
    rownames(bedfiles_chunk) <- bedfiles_chunk$position
    bedfiles_chunk <- bedfiles_chunk %>% dplyr::select(!(position))
    
    # Set sample names
    names(bedfiles_chunk) <- paste0("sample_", sample_names[[chunk]])
    
    # save
    saveRDS(bedfiles_chunk, file = file.path(s_OUT_dir, "Bedmethyl_all/", paste0("bedfiles_", mod_type,"_chunk_",chunk,".rds")))
    gc()
    
    
  })
  
  temp = list.files(file.path(s_OUT_dir, "Bedmethyl_all/"), 
                    pattern=paste0("bedfiles_", mod_type, "_chunk_"), 
                    full.names = TRUE)
  
  bedfiles_all <- readRDS(temp[1]) # Start with first chunk
  
  progress_bar <- txtProgressBar(min=0, max=length(temp)) # Add progress bar
  
  for (i in 2:length(temp)) {
    # Read BED file
    file <- readRDS(temp[i])
    
    
    # Combine methyl values
    bedfiles_all <- merge(bedfiles_all, file, by = "row.names", all=TRUE)
    rownames(bedfiles_all) <- c("Row.names")
    bedfiles_all <- bedfiles_all[,-1]
    
    rm(file)
    gc()
    
    setTxtProgressBar(progress_bar, value = i)
  }
  
  saveRDS(bedfiles_all, file = file.path(s_OUT_dir, "Bedmethyl_all/", paste0("bedfiles_", mod_type,"_all",".rds")))
  gc()
}





# Use combine_perc function for all types of modifications
combine_perc("methyl", chunk_size=50)
combine_perc("hydroxymethyl", chunk_size=40)
combine_perc("modified", chunk_size=40)


